mapper.select:
SELECT 
FROM subscriptions
WHERE userId = #{userId} AND templateId = #{templateId}

mapper.update:
UPDATE subscriptions
SET subscribed = #{subscribed},
    remainCount = #{remainCount}
WHERE id = #{id}

UPDATE subscriptions
SET remainCount = remainCount + #{count}
WHERE id = #{id}

UPDATE subscriptions
SET remainCount = GREATEST(remainCount - 1, 0)
WHERE id = #{id}
